/** UsptEvlCmitDao.selectExistList */ select evl_cmit_id , sect_id , evl_step_id , evl_table_id , evl_cmit_nm , mfcmm_co , evl_prarnde , begin_hour , end_hour , evl_place , orgnzr_id , evl_charmn_opinion_cn , evl_sttus_cd , evl_sttus_dt , slctn_dspth , slctn_dspth_dt , online , attachment_group_id from uspt_evl_cmit where 1 = 1
and sect_id = #{sectId}
and evl_step_id = #{evlStepId}

mapper.insert:
/** UsptEvlCmitDao.insert */
insert into uspt_evl_cmit (
	   evl_cmit_id
	 , sect_id
	 , evl_step_id
	 , evl_table_id
	 , evl_cmit_nm
	 , mfcmm_co
	 , evl_prarnde
	 , begin_hour
	 , end_hour
	 , evl_place
	 , orgnzr_id
	 , evl_charmn_opinion_cn
	 , evl_sttus_cd
	 , evl_sttus_dt
	 , slctn_dspth
	 , slctn_dspth_dt
	 , online
	 , attachment_group_id
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values (
	   #{evlCmitId}
	 , #{sectId}
	 , #{evlStepId}
	 , #{evlTableId}
	 , #{evlCmitNm}
	 , #{mfcmmCo}
	 , #{evlPrarnde}
	 , #{beginHour}
	 , #{endHour}
	 , #{evlPlace}
	 , #{orgnzrId}
	 , #{evlCharmnOpinionCn}
	 , #{evlSttusCd}
	 , #{evlSttusDt}
	 , #{dspth}
	 , #{dspthDt}
	 , #{online}
	 , #{attachmentGroupId}
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

