/** UsptEvlCmitDao.delete */
delete
  from uspt_evl_cmit
 where sect_id in (
 				   select sect_id
                     from uspt_sect
                    where evl_plan_id = #{evlPlanId}
                  )

/** UsptEvlCmitDao.deleteByCmitId */
delete
  from uspt_evl_cmit
 where evl_cmit_id = #{evlCmitId}

