/** UsptEvlCmitDao.updateCmitAttachInfo */
update uspt_evl_cmit
   set evl_sttus_cd       = #{evlSttusCd}
     , evl_sttus_dt  	  = #{evlSttusDt}
	 , updater_id         = #{updaterId}
	 , updated_dt         = #{updatedDt}
where evl_cmit_id = #{evlCmitId}

mapper.select:
/** UsptEvlCmitDao.selectCmitDtaInfo */
select attachment_group_id
 from uspt_evl_cmit
where evl_cmit_id = #{evlCmitId}

/** UsptEvlCmitDao.selectEvlCmitExtrcTargetList */ select c.bsns_year /*사업년도*/ , b.pblanc_nm /*공고명*/ , a.rcept_odr || '차' as rcept_odr /*접수차수*/ , b.ordtm_rcrit /*상시모집여부*/ , case when b.ordtm_rcrit = true then '상시모집' else '정시모집' end as ordtm_rcrit_nm , a.evl_type_cd , fn_cmm_get_code_nm('EVL_TYPE', a.evl_type_cd) as evl_type_nm , d.sect_id , e.evl_step_id , d.sect_nm /*분과명*/ , e.evl_step_nm /*평가단계명*/ , d.evl_plan_id , f.online , f.evl_cmit_id /*평가위원회ID*/ , f.evl_cmit_nm /*위원회명*/ , f.evl_table_id , f.mfcmm_co /*위원수*/ , f.evl_prarnde /*평가예정일*/ , f.begin_hour , f.end_hour , f.evl_place /*평가장소*/ , f.orgnzr_id , fn_cmm_get_member(f.orgnzr_id) as orgnzr_nm /*간사명*/ , f.evl_charmn_opinion_cn , f.evl_sttus_cd , fn_cmm_get_code_nm('EVL_STTUS', f.evl_sttus_cd) as evl_sttus_nm , f.evl_sttus_dt , f.slctn_dspth , case when f.slctn_dspth = true then '완료' else '대기중' end as dspth_nm , f.slctn_dspth_dt , f.online , f.attachment_group_id , case when g.mfcmm_extrc_id != '' then '추출완료' else '대기중' end as process_sttus_nm /*처리상태명*/ , row_number() over (order by f.created_dt desc) as rn from uspt_evl_plan a /*평가계획*/ inner join uspt_bsns_pblanc b /*사업공고*/ on a.pblanc_id = b.pblanc_id inner join uspt_bsns c /*사업*/ on b.bsns_cd = c.bsns_cd inner join uspt_sect d /*분과정보*/ on a.evl_plan_id = d.evl_plan_id inner join uspt_evl_step e /*평가단계*/ on a.evl_plan_id = e.evl_plan_id inner join uspt_evl_cmit f /*평가위원회*/ on d.sect_id = f.sect_id and e.evl_step_id = f.evl_step_id left outer join uspt_evl_mfcmm_extrc g /*평가위원추출*/ on f.evl_cmit_id = g.evl_cmit_id and g.odr_no = 1 where 1 = 1
and c.bsns_year = #{bsnsYear}
and b.pblanc_nm like '%' || #{pblancNm} || '%'
and f.evl_cmit_nm like '%' || #{evlCmitNm} || '%'
and d.sect_nm like '%' || #{sectNm} || '%'
and e.evl_step_nm like '%' || #{evlStepNm} || '%'
and fn_cmm_get_member(f.orgnzr_id) like '%' || #{orgnzrNm} || '%'
and f.evl_sttus_cd like '%' || #{evlSttusCd} || '%'
and a.evl_type_cd = #{evlTypeCd}
and coalesce(f.slctnDspth, false) = #{dspth} and coalesce(f.ptrmsnDspth, false) = #{dspth}
and coalesce(f.online, false) = #{online}
offset #{beginRowNum} -1 limit #{itemsPerPage}

/*UsptEvlCmitDao.selectEvlCmitExtrcTargetCount*/
select (
		select count(b.extrc_mfcmm_id)
		  from uspt_evl_mfcmm_extrc a
			   inner join uspt_extrc_mfcmm b on a.mfcmm_extrc_id  = b.mfcmm_extrc_id
		 where a.evl_cmit_id = #{evlCmitId}
		   and a.odr_no = #{odrNo}
		   and b.lsn_result_cd is null	/*대기*/
		) as wait_co
	  ,(
		select count(b.extrc_mfcmm_id)
		  from uspt_evl_mfcmm_extrc a
			   inner join uspt_extrc_mfcmm b on a.mfcmm_extrc_id  = b.mfcmm_extrc_id
		 where a.evl_cmit_id = #{evlCmitId}
		   and a.odr_no = #{odrNo}
		   and b.lsn_result_cd = 'lire01' /*부재*/
		) as absnce_co
	  ,(
		select count(b.extrc_mfcmm_id)
		  from uspt_evl_mfcmm_extrc a
			   inner join uspt_extrc_mfcmm b on a.mfcmm_extrc_id  = b.mfcmm_extrc_id
		 where a.evl_cmit_id = #{evlCmitId}
		   and a.odr_no = #{odrNo}
		   and b.lsn_result_cd = 'lire02' /*거부*/
	   ) as reject_co
	  ,(
		select count(b.extrc_mfcmm_id)
		  from uspt_evl_mfcmm_extrc a
			   inner join uspt_extrc_mfcmm b on a.mfcmm_extrc_id  = b.mfcmm_extrc_id
		 where a.evl_cmit_id = #{evlCmitId}
		   and a.odr_no = #{odrNo}
		   and b.lsn_result_cd = 'lire03' /*승낙*/
	   ) as confm_co
	  ,(
		select count(b.extrc_mfcmm_id)
		  from uspt_evl_mfcmm_extrc a
			   inner join uspt_extrc_mfcmm b on a.mfcmm_extrc_id  = b.mfcmm_extrc_id
		 where a.evl_cmit_id = #{evlCmitId}
		   and a.odr_no = #{odrNo}
		   and b.lsn_result_cd = 'lire04' /*회피*/
	   ) as evas_co

/** UsptEvlCmitDao.selectEvlCmitExtrcTargetListCount */ select count(a.evl_plan_id) as cnt from uspt_evl_plan a /*평가계획*/ inner join uspt_bsns_pblanc b /*사업공고*/ on a.pblanc_id = b.pblanc_id inner join uspt_bsns c /*사업*/ on b.bsns_cd = c.bsns_cd inner join uspt_sect d /*분과정보*/ on a.evl_plan_id = d.evl_plan_id inner join uspt_evl_step e /*평가단계*/ on a.evl_plan_id = e.evl_plan_id inner join uspt_evl_cmit f /*평가위원회*/ on d.sect_id = f.sect_id and e.evl_step_id = f.evl_step_id left outer join uspt_evl_mfcmm_extrc g /*평가위원추출*/ on f.evl_cmit_id = g.evl_cmit_id and g.odr_no = 1 where 1 = 1
and c.bsns_year = #{bsnsYear}
and b.pblanc_nm like '%' || #{pblancNm} || '%'
and f.evl_cmit_nm like '%' || #{evlCmitNm} || '%'
and d.sect_nm like '%' || #{sectNm} || '%'
and e.evl_step_nm like '%' || #{evlStepNm} || '%'
and fn_cmm_get_member(f.orgnzr_id) like '%' || #{orgnzrNm} || '%'
and f.evl_sttus_cd like '%' || #{evlSttusCd} || '%'
and a.evl_type_cd = #{evlTypeCd}
and coalesce(f.slctn_dspth, false) = #{dspth}
and coalesce(f.online, false) = #{online}

mapper.update:
/** UsptEvlCmitDao.updateCharmOpinion */
update uspt_evl_cmit
   set evl_charmn_opinion_cn     = #{evlCharmnOpinionCn}
	 , updater_id                = #{updaterId}
	 , updated_dt                = #{updatedDt}
where evl_cmit_id = #{evlCmitId}

/** UsptEvlCmitDao.updateSndngInfo */
update uspt_evl_cmit
   set sndng_mth = #{sndngMth}
	 , sndng_cn  = #{sndngCn}

	 , sms_id = #{smsId}


	 , email_id = #{emailId}

where evl_cmit_id = #{evlCmitId}

mapper.select:
/** UsptEvlCmitDao.selectEvlTargetListCount */ select count(sub.evl_cmit_id) from ( select uec.evl_cmit_id , case when uec.slctn_dspth = true then case when uec.ptrmsn_dspth = true then 'COMPT' else 'ING' end else case when uec.ptrmsn_dspth = true then 'ING' else '' end end as dspth_sttus from uspt_evl_cmit uec inner join uspt_evl_step ues on ues.evl_step_id = uec.evl_step_id inner join uspt_sect us on us.sect_id = uec.sect_id inner join uspt_evl_plan uep on uep.evl_plan_id = ues.evl_plan_id and uep.evl_plan_id = us.evl_plan_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = uep.pblanc_id and ubpr.rcept_odr = uep.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId} inner join cmmt_insider ci on ci.member_id = uec.orgnzr_id
) sub
sub.dspth_sttus = #{dspthSttus}

/** UsptEvlCmitDao.selectEvlTargetList */ select sub.* , row_number() over (order by sub.created_dt desc) as rn from ( select uec.evl_cmit_id , uec.evl_cmit_nm , uec.evl_sttus_cd , uec.evl_sttus_dt , uec.created_dt , case when uec.online = true then 'ON' else 'OFF' end as evl_mth , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@EVL_STTUS_CODE_GROUP}', uec.evl_sttus_cd) as evl_sttus_nm , uec.orgnzr_id , uec.evl_prarnde , uec.orgnzr_id , ci.member_nm as orgnzr_nm , ub.bsns_year , ubp.pblanc_nm , uep.evl_type_cd , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@EVL_TYPE_CODE_GROUP}', uep.evl_type_cd) as evl_type_nm , ues.evl_step_nm , us.sect_nm , case when ubp.ordtm_rcrit = true then '상시모집' else '정시모집' end as ordtm_rcrit_nm , case when ubp.ordtm_rcrit = true then concat(ubpr.rcept_odr, '차') else '' end as rcept_odr , case when uec.slctn_dspth = true then case when uec.ptrmsn_dspth = true then 'COMPT' else 'ING' end else case when uec.ptrmsn_dspth = true then 'ING' else '' end end as dspth_sttus , uet.evl_mthd_cd , ubc.charger_author_cd from uspt_evl_cmit uec inner join uspt_evl_table uet on uet.evl_table_id = uec.evl_table_id and uet.enabled = true inner join uspt_evl_step ues on ues.evl_step_id = uec.evl_step_id inner join uspt_sect us on us.sect_id = uec.sect_id inner join uspt_evl_plan uep on uep.evl_plan_id = ues.evl_plan_id and uep.evl_plan_id = us.evl_plan_id inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = uep.pblanc_id and ubpr.rcept_odr = uep.rcept_odr inner join uspt_bsns_pblanc ubp on ubp.pblanc_id = ubpr.pblanc_id inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId} inner join cmmt_insider ci on ci.member_id = uec.orgnzr_id
) sub
sub.dspth_sttus = #{dspthSttus}
